        	  TKEXAM_HSTRY_ID
			, USER_ID
			, EXAM_DTL_ID
			, HSTRY_GBNCD
			, TKEXAM_CNT
			, TOT_SCR
			, TKEXAM_MNTS
			, TKEXAM_SDTTM
			, TKEXAM_EDTTM
			, EVLYN
			, EVL_DTTM
			, RGTR_ID
			, REG_DTTM
			, TKEXAM_IP
        ) VALUES (
        	  #{tkexamHstryId}
			, #{userId}
			, #{examDtlId}
			, #{hstryGbncd}
			, #{tkexamCnt}
			, #{totScr}
			, #{tkexamMnts}
			, #{tkexamSdttm}
			, #{tkexamEdttm}
			, #{evlyn}
			, #{evlDttm}
			, #{rgtrId}
			, FN_DTTM()
			, #{tkexamIp}
        )
